const data = $input.first().json;

let memory = {};
try {
  const stored = $getWorkflowStaticData('global');
  memory = stored.videoMemory || {};
} catch(e) { memory = {}; }

if (!memory.totalVideos) memory.totalVideos = 0;
if (!memory.lastTopics) memory.lastTopics = [];
if (!memory.nichePerformance) memory.nichePerformance = {};
if (!memory.preferredStyle) memory.preferredStyle = 'cinematic documentary';
if (!memory.bestPerformingNiche) memory.bestPerformingNiche = 'general';
if (!memory.channelName) memory.channelName = 'Empires Untold';
if (!memory.defaultVoice) memory.defaultVoice = 'Max';
if (!memory.voicePerformance) memory.voicePerformance = {};
if (!memory.bestVoicePerNiche) memory.bestVoicePerNiche = {};
if (!memory.totalCost) memory.totalCost = 0;
if (!memory.seriesData) memory.seriesData = {};
if (!memory.qualityScores) memory.qualityScores = [];

memory.totalVideos += 1;

const topic = data.customTopic || 'auto';
memory.lastTopics.unshift(topic);
if (memory.lastTopics.length > 20) memory.lastTopics = memory.lastTopics.slice(0,20);

const niche = data.niche || 'general';
if (!memory.nichePerformance[niche]) memory.nichePerformance[niche] = { count: 0, avgViews: 0 };
memory.nichePerformance[niche].count += 1;

let bestNiche = 'general', bestCount = 0;
for (const [n, s] of Object.entries(memory.nichePerformance)) {
  if (s.count > bestCount) { bestNiche = n; bestCount = s.count; }
}
memory.bestPerformingNiche = bestNiche;

if (data.seriesName) {
  if (!memory.seriesData[data.seriesName]) memory.seriesData[data.seriesName] = { episodes: 0, lastEp: 0 };
  memory.seriesData[data.seriesName].episodes += 1;
  memory.seriesData[data.seriesName].lastEp = parseInt(data.seriesEp || 1);
}

try {
  const stored = $getWorkflowStaticData('global');
  stored.videoMemory = memory;
} catch(e) {}

return [{ json: {
  ...data,
  memory: {
    totalVideos: memory.totalVideos,
    recentTopics: memory.lastTopics.slice(0,5),
    bestNiche: memory.bestPerformingNiche,
    preferredStyle: memory.preferredStyle,
    channelName: memory.channelName,
    avoidRepeat: memory.lastTopics.slice(0,3),
    defaultVoice: memory.defaultVoice,
    bestVoicePerNiche: memory.bestVoicePerNiche,
    totalCost: memory.totalCost,
    seriesData: memory.seriesData,
    qualityScores: memory.qualityScores.slice(0,10)
  }
}}];

const stored = $getWorkflowStaticData('global');
const memory = stored.videoMemory || {};
