return [{ json: { ...($input.first().json), costReport } }];

const stored = $getWorkflowStaticData('global');
const log = (stored.securityLog || []).slice(0,20);
let msg = 'Security Log - Last 20 Events:\n\n';
if (log.length === 0) {
  msg += 'No events recorded yet.';
} else {
  log.forEach((e, i) => {
    const time = e.ts ? e.ts.slice(5,19).replace('T',' ') : '?';
    const status = e.blocked ? `BLOCKED [${e.reason || 'unknown'}]` : 'OK';
    msg += `${i+1}. [${time}] ${e.action || e.cmd || 'cmd'} from ${e.chatId || '?'} (${e.src || '?'}) - ${status}\n`;
  });
}
return [{ json: { ...($input.first().json), securityLogMsg: msg } }];

const stored = $getWorkflowStaticData('global');
const memory = stored.videoMemory || {};
const voicePerf = memory.voicePerformance || {};
const bestPerNiche = memory.bestVoicePerNiche || {};
