const stored = $getWorkflowStaticData('global');
const d = stored.pendingVideoData || {};
const thumbUrl = stored.selectedThumbUrl || d.thumbUrl || '';

const vids = d.videoUrls || [];
const segs = d.script_segments || [];
const dur = d.estimated_duration || 58;
const isShorts = dur <= 70;
const clipDur = isShorts ? 2.5 : 4.5;
const channelName = (d.memory || {}).channelName || 'Empires Untold';
const thumbnailText = (d.thumbnail_text || '').toUpperCase().split(' ').slice(0, 5).join(' ');
const hookText = (d.hook || '').split(' ').slice(0, 8).join(' ').toUpperCase() || 'THE TRUTH THEY NEVER TOLD YOU';
const textPos = d.thumbnail_text_position === 'top' ? '11%' : '83%';

// Cinematic video clips with transitions - whip pan left/right/up
const clipCount = Math.min(vids.length, Math.ceil(dur / clipDur) + 1);
const videoClips = vids.slice(0, clipCount).map((url, i) => ({
  type: 'video', track: 1,
  time: parseFloat((i * clipDur).toFixed(2)),
  duration: parseFloat((clipDur + 0.4).toFixed(2)),
  source: url, fit: 'cover', volume: '0%',
  ...(i > 0 ? { enter: { effect: 'slide', duration: 0.2, direction: ['right', 'left', 'up', 'down'][i % 4] } } : {})
}));

// Hook caption - first 3 seconds, full screen dramatic, high impact
const hookCaption = {
  type: 'text', track: 3, time: 0.1, duration: 2.7,
  text: hookText,
  font_family: 'Montserrat', font_weight: '900', font_size: '86px',
  fill_color: '#FFFFFF', stroke_color: '#000000', stroke_width: '5px',
  x_alignment: '50%', y_alignment: '50%', width: '90%',
  background_color: 'rgba(0,0,0,0.55)',
  background_x_padding: '20px', background_y_padding: '14px',
  enter: { effect: 'scale', duration: 0.3, easing: 'bounce-out' },
  exit: { effect: 'fade', duration: 0.2 }
};

// Cinematic captions - Montserrat 900, word-by-word style animation
const captionClips = segs.slice(0, 14).map((seg, i) => {
  const startTime = parseFloat((3 + i * ((dur - 4) / Math.max(segs.length, 1))).toFixed(2));
  const segDur = parseFloat(((dur - 4) / Math.max(segs.length, 1) - 0.05).toFixed(2));
  const text = (seg.caption || (seg.text || '').slice(0, 75) || '').trim();
  const hasNumbers = /\d/.test(text);
  const isKeyWord = /\b(NEVER|SECRET|TRUTH|HIDDEN|REAL|ONLY|FIRST|FINAL|WARNING|BREAKING|SHOCKING|EXPOSED|REVEALED)\b/i.test(text);

  return {
    type: 'text', track: 3,
    time: startTime, duration: Math.max(segDur, 0.5),
    text,
    font_family: 'Montserrat', font_weight: '900',
    font_size: hasNumbers ? '80px' : (isKeyWord ? '72px' : '64px'),
    fill_color: hasNumbers ? '#FFD700' : (isKeyWord ? '#FF4B4B' : '#FFFFFF'),
    stroke_color: '#000000', stroke_width: '3px',
    x_alignment: '50%', y_alignment: '85%', width: '88%',
    enter: { effect: 'scale', duration: 0.1, easing: 'bounce-out' },
    exit: { effect: 'fade', duration: 0.07 }
  };
});

// Channel watermark
const watermark = {
  type: 'text', track: 4, time: 0, duration: dur,
  text: channelName, font_family: 'Montserrat', font_weight: '700', font_size: '22px',
  fill_color: '#FFFFFF', x_alignment: '50%', y_alignment: '4%',
  opacity: '80%', background_color: 'rgba(0,0,0,0.35)',
  background_x_padding: '12px', background_y_padding: '4px'
};

// Subscribe pulse animation - red button bounce in
const subscribeAnim = {
  type: 'text', track: 5,
  time: parseFloat(Math.max(dur - 6, 0).toFixed(2)), duration: 6,
  text: 'SUBSCRIBE', font_family: 'Montserrat', font_weight: '900', font_size: '52px',
  fill_color: '#FFFFFF', background_color: '#FF0000',
  background_x_padding: '24px', background_y_padding: '12px',
  x_alignment: '50%', y_alignment: '50%',
  enter: { effect: 'scale', duration: 0.5, easing: 'bounce-out' }
};

// Thumbnail text overlay - Montserrat Black, white + black stroke, top or bottom third
const thumbTextEl = thumbnailText ? {
  type: 'text', track: 6, time: 0, duration: dur,
  text: thumbnailText, font_family: 'Montserrat', font_weight: '900', font_size: '68px',
  fill_color: '#FFFFFF', stroke_color: '#000000', stroke_width: '4px',
  x_alignment: '50%', y_alignment: textPos, width: '84%'
} : null;

const elements = [...videoClips, hookCaption, ...captionClips, watermark, subscribeAnim];
if (thumbTextEl) elements.push(thumbTextEl);

const creatomateSource = {
  output_format: 'mp4', width: 1080, height: 1920, frame_rate: 30, duration: dur,
  elements
};

