const raw = $input.first().json;
const txt = raw.content?.[0]?.text || '{}';
let trans = {};
try { const m = txt.match(/\{[\s\S]*\}/); trans = m ? JSON.parse(m[0]) : {}; } catch(e) {}
const stored = $getWorkflowStaticData('global');
const base = stored.pendingVideoData || {};
return [{ json: {
  ...base,
  hindi_title: trans.hindi_title || base.title,
  hindi_voiceover: trans.hindi_voiceover || base.voiceover_full,
  hindi_description: trans.hindi_description || base.description,
  hindi_hook: trans.hindi_hook || base.hook,
  transliterated_title: trans.transliterated_title || '',
  tags_hindi: trans.tags_hindi || base.tags || [],
  translationDone: true
}}];

const stored = $getWorkflowStaticData('global');
const memory = stored.videoMemory || {};
return [{ json: { memory, monthlyCost: stored.monthlyCost || 0, checkDate: new Date().toISOString() } }];

const d = $input.first().json;
const stored = $getWorkflowStaticData('global');

const score = (d.qualityScore || {}).total_score || 0;
const hookScore = (d.qualityScore || {}).hook_score || 0;
const viralScore = (d.qualityScore || {}).viral_score || 0;
const topic = d.topic || d.customTopic || d.niche || 'general';

if (!stored.topicScores) stored.topicScores = {};
if (!stored.highScoringTopics) stored.highScoringTopics = [];

const entry = stored.topicScores[topic] || { count: 0, totalScore: 0, avgScore: 0, lastScore: 0 };
entry.count += 1;
entry.totalScore += score;
entry.avgScore = parseFloat((entry.totalScore / entry.count).toFixed(1));
entry.lastScore = score;
stored.topicScores[topic] = entry;

if (score >= 42) {
  stored.highScoringTopics.unshift({ topic, score, hookScore, viralScore, date: new Date().toISOString().split('T')[0] });
  if (stored.highScoringTopics.length > 30) stored.highScoringTopics = stored.highScoringTopics.slice(0, 30);
}

const topicWords = topic.toLowerCase().split(' ').filter(w => w.length > 4);
const similarTopics = (stored.highScoringTopics || [])
  .filter(t => t.topic !== topic && topicWords.some(w => t.topic.toLowerCase().includes(w)))
  .slice(0, 3)
  .map(t => t.topic + ' (scored ' + t.score + ')');

const topPerformers = Object.entries(stored.topicScores || {})
  .filter(([, v]) => v.count > 0)
  .sort((a, b) => b[1].avgScore - a[1].avgScore)
  .slice(0, 5)
  .map(([t, v]) => t + ': avg ' + v.avgScore);

return [{ json: { ...d, qualityInsights: {
  topicAvgScore: entry.avgScore,
  topicVideoCount: entry.count,
  similarHighTopics: similarTopics,
  topPerformers
} } }];

