const stored = $getWorkflowStaticData('global');
const renderData = $input.first().json;
const isArr = Array.isArray(renderData);
const item = isArr ? renderData[0] : renderData;
const status = (item && item.status) || '';
const url = (item && (item.url || item.snapshot_url)) || '';
const renderId = (item && item.id) || '';

if (status === 'succeeded' && url) {
  stored.renderRetryCount = 0;
  return [{ json: { ...item, url, renderDone: true } }];
}

if (status === 'failed') {
  stored.renderRetryCount = 0;
  const errMsg = (item && item.error_message) || 'Render failed';
  return [{ json: { error: true, errorMsg: 'Render failed: ' + errMsg, renderId, renderDone: false } }];
}

const retryCount = (stored.renderRetryCount || 0) + 1;
stored.renderRetryCount = retryCount;

if (retryCount >= 5) {
  stored.renderRetryCount = 0;
  return [{ json: { error: true, errorMsg: 'Render timed out after 5 retries. Last status: ' + status, renderId, renderDone: false } }];
}

return [{ json: { ...(item || {}), renderDone: false, retryCount, renderId, renderStatus: status } }];
